// Normalize GitLab push/merge_request webhook payloads
const body = $input.first().json.body || $input.first().json;
const oa = body.object_attributes || {};
const ref = oa.ref || body.ref || '';
const branch = ref.split('/').slice(2).join('/') || ref;
const sha = oa.sha || body.checkout_sha || body.after || '';
const source = oa.source || body.object_kind || 'push';
const projectId = body.project_id ||
  (body.project && body.project.id) ||
  oa.project_id || 0;
const commitMsg = (body.commits && body.commits[0] && body.commits[0].message) ||
  (body.commit && body.commit.title) ||
  oa.title || '';
const author = (body.commits && body.commits[0] && body.commits[0].author && body.commits[0].author.name) ||
  body.user_name || 'Unknown';

return [{
  json: {
    branch,
    ref,
    sha: sha.substring(0, 8),
    sha_full: sha,
    source,
    isMaster: branch === 'master' || branch === 'main',
    projectId: String(projectId),
    commitMsg: commitMsg.split('\n')[0].substring(0, 100),
    author,
    triggeredAt: new Date().toISOString()
  }
}];

// Format pipeline creation error notification payload
const errorResp = $input.first().json;
const info = $('extract-info').first().json;
const gitlabUrl = $env.GITLAB_URL || 'https://gitlab.jclee.me';
const errorMsg = errorResp.message || errorResp.error || JSON.stringify(errorResp);

return [{
  json: {
    event: 'ci-pipeline-create-error',
    status: 'error',
    conclusion: 'failure',
    pipeline_id: null,
    passed: 0,
    failed: 0,
    total: 0,
    duration_seconds: 0,
    commit: info.sha,
    commit_message: info.commitMsg,
    author: info.author,
    ref: info.ref,
    project_id: info.projectId,
    url: `${gitlabUrl}/${info.projectId}/-/pipelines`,
    timestamp: new Date().toISOString(),
    message: `❌ CI 파이프라인 생성 실패\n\n브랜치: ${info.branch}\nSHA: ${info.sha}\n\n오류: ${errorMsg}`
  }
}];

// Merge pipeline creation response with original webhook data into a single poll state object
const pipeline = $input.first().json;
const info = $('extract-info').first().json;

return [{
  json: {
    project_id: info.projectId,
    pipeline_id: pipeline.id,
    pipeline_web_url: pipeline.web_url || '',
    ref: info.ref,
    branch: info.branch,
    commit: info.sha,
    commit_full: info.sha_full,
    commit_message: info.commitMsg,
    author: info.author,
    source: info.source,
    started_at: new Date().toISOString()
  }
}];

// Poll GitLab pipeline status until terminal state or timeout (60 polls x 30s = 30min max).
// Uses fetch() available in n8n Code nodes on Node.js 18+.
const state = $input.first().json;
const { project_id, pipeline_id, ref, commit, started_at } = state;

const gitlabUrl = ($env.GITLAB_URL || 'https://gitlab.jclee.me').replace(/\/+$/, '');
const gitlabToken = $env.GITLAB_TOKEN;

if (!gitlabToken) {
  throw new Error('GITLAB_TOKEN environment variable is not set');
}

const headers = { 'PRIVATE-TOKEN': gitlabToken };
const terminalStatuses = ['success', 'failed', 'cancelled', 'canceled', 'skipped'];
const maxPolls = 60;
const pollIntervalMs = 30000; // 30초

let pipelineStatus = 'pending';
let pollCount = 0;

console.log(`[CI 파이프라인 시작됨] pipeline_id=${pipeline_id} project_id=${project_id} ref=${ref}`);

while (pollCount < maxPolls) {
  const pollUrl = `${gitlabUrl}/api/v4/projects/${encodeURIComponent(String(project_id))}/pipelines/${pipeline_id}`;
  let res;
  try {
    res = await fetch(pollUrl, { headers });
  } catch (fetchErr) {
    console.error(`Poll ${pollCount + 1}: fetch error — ${fetchErr.message}`);
    pipelineStatus = 'poll_error';
    break;
  }

  if (!res.ok) {
    const errText = await res.text().catch(() => String(res.status));
    console.error(`Poll ${pollCount + 1}: HTTP ${res.status} — ${errText}`);
    pipelineStatus = 'poll_error';
    break;
  }

  const pipeline = await res.json();
  pipelineStatus = pipeline.status;
  console.log(`Poll ${pollCount + 1}/${maxPolls}: status=${pipelineStatus}`);

  if (terminalStatuses.includes(pipelineStatus)) {
    break;
  }

  pollCount++;
  if (pollCount < maxPolls) {
    await new Promise(r => setTimeout(r, pollIntervalMs));
  }
}

if (!terminalStatuses.includes(pipelineStatus)) {
  pipelineStatus = 'timeout';
}

const completedAt = new Date().toISOString();
const durationSeconds = Math.round((new Date(completedAt) - new Date(started_at)) / 1000);

console.log(`[파이프라인 완료] status=${pipelineStatus} duration=${durationSeconds}s polls=${pollCount}`);

return [{
  json: {
    ...state,
    pipelineStatus,
    pollCount,
    completed_at: completedAt,
    duration_seconds: durationSeconds
  }
}];

// Build Korean notification summary from poll state + job results
const pollState = $('poll-pipeline').first().json;

// Handle both array-in-single-item and split-item responses from HTTP GET
const rawItems = $input.all();
let jobs = [];
if (rawItems.length === 1 && Array.isArray(rawItems[0].json)) {
  jobs = rawItems[0].json;
} else {
  jobs = rawItems.map(item => item.json).filter(j => j && j.id);
}

const passed  = jobs.filter(j => j.status === 'success').length;
const failed  = jobs.filter(j => j.status === 'failed').length;
const skipped = jobs.filter(j => ['skipped', 'manual', 'canceled'].includes(j.status)).length;
const total   = jobs.length;

const {
  pipelineStatus, pipeline_id, pipeline_web_url,
  ref, commit, commit_message, author,
  project_id, duration_seconds
} = pollState;

const durationMinutes = Math.floor(duration_seconds / 60);
const durationSecs    = duration_seconds % 60;
const durationText    = durationMinutes > 0
  ? `${durationMinutes}분 ${durationSecs}초`
  : `${durationSecs}초`;

let statusEmoji, statusKr;
switch (pipelineStatus) {
  case 'success':    statusEmoji = '✅'; statusKr = 'CI 파이프라인 완료';    break;
  case 'failed':     statusEmoji = '❌'; statusKr = 'CI 파이프라인 실패';    break;
  case 'cancelled':
  case 'canceled':   statusEmoji = '⏹️'; statusKr = 'CI 파이프라인 취소됨'; break;
  case 'timeout':    statusEmoji = '⏱️'; statusKr = 'CI 파이프라인 시간초과'; break;
  case 'poll_error': statusEmoji = '⚠️'; statusKr = 'CI 파이프라인 폴링 오류'; break;
  default:           statusEmoji = '❓'; statusKr = `CI 파이프라인: ${pipelineStatus}`;
}

const gitlabUrl   = ($env.GITLAB_URL || 'https://gitlab.jclee.me').replace(/\/+$/, '');
const pipelineUrl = pipeline_web_url || `${gitlabUrl}/${project_id}/-/pipelines/${pipeline_id}`;
const branchName  = (ref || '').replace('refs/heads/', '');
const failedNames = jobs.filter(j => j.status === 'failed').map(j => j.name).slice(0, 5);

const lines = [
  `${statusEmoji} ${statusKr}`,
  '',
  `브랜치: ${branchName}`,
  `SHA: ${commit}`,
  `커밋: ${commit_message}`,
  `작성자: ${author}`,
  '',
  `결과: ✅ ${passed} / ❌ ${failed} / 전체 ${total}`,
  `소요시간: ${durationText}`,
  failedNames.length ? `실패 잡: ${failedNames.join(', ')}` : null,
  '',
  `파이프라인: #${pipeline_id}`
].filter(line => line !== null);

const conclusion = pipelineStatus === 'success' ? 'success' : 'failure';

return [{
  json: {
    event: 'ci-pipeline-complete',
    status: pipelineStatus,
    conclusion,
    pipeline_id: String(pipeline_id),
    passed,
    failed,
    skipped,
    total,
    duration_seconds,
    commit,
    commit_message,
    author,
    ref,
    project_id: String(project_id),
    url: pipelineUrl,
    timestamp: new Date().toISOString(),
    message: lines.join('\n')
  }
}];
